const { execSync } = require('child_process');
const data = $input.item.json;
const val = (data.query && data.query.run_id) ? data.query.run_id : data.run_id;
if (!val) { return [{ json: { stdout: '', stderr: 'No run_id provided. Got: ' + JSON.stringify(data) } }]; }
try {
  const cmd = 'gh run view ' + val + ' --log-failed | tail -n 200';
  const stdout = execSync(cmd, { encoding: 'utf8', timeout: 30000 });
  return [{ json: { stdout: stdout || 'Done.', stderr: '' } }];
} catch(e) {
  return [{ json: { stdout: e.stdout || '', stderr: e.stderr || e.message } }];
}
